{
  "narrative": "你拿出一小包货物和粗壮的胳膊，问领队是否需要帮手。他扫了一眼你的包袱，又看看你，没有立刻回答，只是朝车尾努了努嘴——那里堆着几捆未固定的皮革。旁边一个老短工低声说：‘先干点活再说。’你仍然只是候选，未被正式接纳。",
  "identity_route_pressure": [
    "商队短工候选人：需要展示劳力或货物交换条件",
    "保持低阶劳工身份压力"
  ],
  "same_start_variant": [
    "直接上前搬起一捆皮革示范力气",
    "先询问工钱和伙食再展示货物"
  ],
  "safe_next_steps": [
    "主动去帮忙固定皮革，不向领队直接索取承诺",
    "观察其他短工如何与护卫相处，学习规矩"
  ],
  "boundary_notes": [
    "仅作投影，不是正式结论",
    "商队暂未给予任何正式身份、报酬或驻地"
  ]
}

{
  "narrative": "你试探性地问领队自己是否算正式加入了。领队头也不抬地摆摆手：‘先干几天活，看看货能不能保全再说。这里没有名册，也不发凭据，想留下就拿出本事。’老短工低声补了一句：‘小心点，别太急着攀关系。’你仍然只是候选，许可来自行动而非文书。",
  "identity_route_pressure": [
    "商队短工候选人：靠持续出力换取口头许可",
    "需展示体力或货物交换价值",
    "不可索要名册或凭证"
  ],
  "same_start_variant": [
    "默默加固车尾绳索，不追问归属",
    "递给领队一小块盐巴，暗示交易而非索要地位"
  ],
  "safe_next_steps": [
    "继续帮助固定皮革，少言多劳",
    "留意护卫如何警戒，不主动越界"
  ],
  "boundary_notes": [
    "仅作投影，不是正式结论",
    "未批准任何凭据、名册或正式成员身份"
  ]
}

{
  "narrative": "你刚提到价格表和库存，领队就皱起眉头：‘这趟还没定下采购价，货也还没清点。你一个干短活的，打听这些太早了。真要谈，先干满三天活再说。’老短工在旁摇头：‘没通过考察之前，连货物总数都不该问。现在你只有候选身份，别越位。’",
  "identity_route_pressure": [
    "商队短工候选人：通过持续体力活换取口头许可",
    "展示货物处理能力或交易价值才能获得进一步信任"
  ],
  "same_start_variant": [
    "默默整理车尾防水布，不问价格",
    "帮领队清点绳索数量，暗示自己懂物资管理"
  ],
  "safe_next_steps": [
    "继续帮忙固定货物，少言多劳",
    "留心护卫如何交接货物清单，但不过问"
  ],
  "boundary_notes": [
    "仅作投影，不是正式结论",
    "价格表和库存是后续门禁，当前无权获取"
  ]
}
